1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
7	
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
18	type QuoteStep = { op: "quote"; items: Item[] };
19	type Scenario = { steps: [QuoteStep] };
20	
21	const quoteResult = (premium: number) => ({ results: [{ premium }] });
22	
23	const sum = (numbers: number[]): number =>
24	  numbers.reduce((total, n) => total + n, 0);
25	
26	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type];
27	
28	const isBlockOfThreeAlike = (items: Item[]): boolean =>
29	  items.length === 3 && items.every((item) => item.type === items[0].type);
30	
31	const groupByType = (items: Item[]): Item[][] => {
32	  const groups: Record<string, Item[]> = {};
33	  for (const item of items) {
34	    (groups[item.type] ||= []).push(item);
35	  }
36	  return Object.values(groups);
37	};
38	
39	const groupBasePremium = (group: Item[]): number =>
40	  isBlockOfThreeAlike(group)
41	    ? BLOCK_OF_THREE_BASE_PREMIUM
42	    : sum(group.map(itemBasePremium));
43	
44	const itemsBasePremium = (items: Item[]): number =>
45	  sum(groupByType(items).map(groupBasePremium));
46	
47	const cursedSurcharge = (item: Item): number =>
48	  item.cursed ? itemBasePremium(item) * CURSED_SURCHARGE_RATE : 0;
49	
50	const highEnchantmentSurcharge = (item: Item): number =>
51	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
52	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
53	    : 0;
54	
55	const itemSurchargesTotal = (items: Item[]): number =>
56	  sum(items.map((item) => cursedSurcharge(item) + highEnchantmentSurcharge(item)));
57	
58	const applyFirstInsuranceSurcharge = (amount: number): number =>
59	  amount + amount * FIRST_INSURANCE_SURCHARGE_RATE;
60	
61	const quotePremiumFor = (items: Item[]): number =>
62	  Math.ceil(
63	    applyFirstInsuranceSurcharge(itemsBasePremium(items)) +
64	      itemSurchargesTotal(items) +
65	      PROCESSING_FEE,
66	  );
67	
68	export const runScenario = (input: Scenario): unknown =>
69	  quoteResult(quotePremiumFor(input.steps[0].items));
